import { useState, useEffect, useRef, useCallback } from "react"
import { cn } from "@/lib/utils"

interface CountdownTimerProps {
  startTime: string
  timeLimitMin: number
  onTimeUp: () => void
}

/** 将秒数格式化为 MM:SS */
function formatTime(totalSeconds: number): string {
  const mins = Math.floor(totalSeconds / 60)
  const secs = totalSeconds % 60
  return `${String(mins).padStart(2, "0")}:${String(secs).padStart(2, "0")}`
}

/** 计算剩余秒数 */
function calcRemaining(startTime: string, timeLimitMin: number): number {
  const elapsed = Math.floor(
    (Date.now() - new Date(startTime).getTime()) / 1000,
  )
  return Math.max(0, timeLimitMin * 60 - elapsed)
}

export function CountdownTimer({
  startTime,
  timeLimitMin,
  onTimeUp,
}: CountdownTimerProps) {
  const [remaining, setRemaining] = useState(() =>
    calcRemaining(startTime, timeLimitMin),
  )
  const timeUpCalledRef = useRef(false)
  const onTimeUpRef = useRef(onTimeUp)
  onTimeUpRef.current = onTimeUp

  const checkTimeUp = useCallback((secs: number) => {
    if (secs <= 0 && !timeUpCalledRef.current) {
      timeUpCalledRef.current = true
      onTimeUpRef.current()
    }
  }, [])

  useEffect(() => {
    const interval = setInterval(() => {
      const secs = calcRemaining(startTime, timeLimitMin)
      setRemaining(secs)
      checkTimeUp(secs)

      // 时间到后清除定时器
      if (secs <= 0) {
        clearInterval(interval)
      }
    }, 1000)

    return () => clearInterval(interval)
  }, [startTime, timeLimitMin, checkTimeUp])

  const isUrgent = remaining < 60

  return (
    <span
      className={cn(
        "font-mono text-lg font-semibold",
        isUrgent && "animate-pulse text-red-600",
      )}
    >
      {formatTime(remaining)}
    </span>
  )
}

import { useState } from "react"
import { createFileRoute, useNavigate } from "@tanstack/react-router"
import { useTranslation } from "react-i18next"
import { Button } from "@/components/ui/button"
import { ExamCard } from "@/components/exam-card"
import { useExamList } from "@/hooks/use-exams"

export const Route = createFileRoute("/_layout/exams/")({
  component: ExamListPage,
})

function ExamListPage() {
  const { t } = useTranslation()
  const navigate = useNavigate()
  const [page, setPage] = useState(1)
  const pageSize = 12
  const { data, isLoading } = useExamList(page, pageSize)

  const totalPages = data ? Math.ceil(data.total / pageSize) : 0

  return (
    <div className="space-y-6">
      <h1 className="text-xl font-semibold">{t("nav.myExams")}</h1>

      {isLoading ? (
        <div className="py-10 text-center text-muted-foreground">
          {t("common.loading")}
        </div>
      ) : !data?.records.length ? (
        <div className="py-10 text-center text-muted-foreground">
          {t("exam.noExams")}
        </div>
      ) : (
        <>
          {/* 试卷卡片网格 */}
          <div className="grid grid-cols-1 gap-4 md:grid-cols-2 lg:grid-cols-3">
            {data.records.map((exam) => (
              <ExamCard
                key={exam.id}
                exam={exam}
                onClick={() => navigate({ to: `/exams/${exam.id}` })}
              />
            ))}
          </div>

          {/* 分页 */}
          {totalPages > 1 && (
            <div className="flex items-center justify-end gap-2">
              <Button
                variant="outline"
                size="sm"
                disabled={page <= 1}
                onClick={() => setPage((p) => p - 1)}
              >
                {t("exam.prevPage")}
              </Button>
              <span className="text-sm text-muted-foreground">
                {page} / {totalPages}
              </span>
              <Button
                variant="outline"
                size="sm"
                disabled={page >= totalPages}
                onClick={() => setPage((p) => p + 1)}
              >
                {t("exam.nextPage")}
              </Button>
            </div>
          )}
        </>
      )}
    </div>
  )
}

import { useState } from "react"
import { createFileRoute, useNavigate } from "@tanstack/react-router"
import { useTranslation } from "react-i18next"
import { toast } from "sonner"
import { Clock, FileQuestion, RotateCcw } from "lucide-react"
import { Button } from "@/components/ui/button"
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
  DialogFooter,
} from "@/components/ui/dialog"
import { useExamDetail, useStartExam } from "@/hooks/use-exams"

export const Route = createFileRoute("/_layout/exams/$id")({
  component: ExamDetailPage,
})

function ExamDetailPage() {
  const { t } = useTranslation()
  const navigate = useNavigate()
  const { id } = Route.useParams()
  const examId = Number(id)
  const { data: exam, isLoading } = useExamDetail(examId)
  const startMutation = useStartExam()
  const [showConfirm, setShowConfirm] = useState(false)

  const handleStart = () => {
    startMutation.mutate(examId, {
      onSuccess: (res) => {
        // 携带考试状态导航到答题页面
        navigate({
          to: `/exams/${examId}/take`,
          state: {
            recordId: res.recordId,
            questions: res.questions,
            startTime: new Date().toISOString(),
            timeLimitMin: exam!.timeLimitMin,
            examTitle: exam!.title,
          },
        })
      },
      onError: (err) => {
        toast.error(err.message)
        setShowConfirm(false)
      },
    })
  }

  if (isLoading) {
    return (
      <div className="py-10 text-center text-muted-foreground">
        {t("common.loading")}
      </div>
    )
  }

  if (!exam) {
    return (
      <div className="py-10 text-center text-muted-foreground">
        {t("common.noData")}
      </div>
    )
  }

  const timeDisplay =
    exam.timeLimitMin > 0
      ? t("exam.timeLimitValue", { min: exam.timeLimitMin })
      : t("exam.noTimeLimit")

  const attemptsDisplay =
    exam.remainingAttempts === null
      ? t("exam.unlimited")
      : t("exam.attemptsValue", { count: exam.remainingAttempts })

  const canStart = exam.remainingAttempts === null || exam.remainingAttempts > 0

  return (
    <div className="mx-auto max-w-lg space-y-6">
      {/* 考试信息卡 */}
      <div className="rounded-lg border p-6 space-y-4">
        <h1 className="text-2xl font-bold">{exam.title}</h1>

        <div className="space-y-3 text-sm text-muted-foreground">
          <div className="flex items-center gap-2">
            <FileQuestion className="h-4 w-4" />
            <span>
              {t("exam.questionCountLabel")}: {exam.questionCount}
              {t("exam.questionUnit")}
            </span>
          </div>
          <div className="flex items-center gap-2">
            <Clock className="h-4 w-4" />
            <span>
              {t("exam.timeLimitLabel")}: {timeDisplay}
            </span>
          </div>
          <div className="flex items-center gap-2">
            <RotateCcw className="h-4 w-4" />
            <span>
              {t("exam.remainingAttemptsLabel")}: {attemptsDisplay}
            </span>
          </div>
        </div>

        <Button
          className="w-full"
          size="lg"
          disabled={!canStart}
          onClick={() => setShowConfirm(true)}
        >
          {t("exam.startExam")}
        </Button>

        {!canStart && (
          <p className="text-center text-sm text-destructive">
            {t("exam.noAttemptsLeft")}
          </p>
        )}
      </div>

      {/* 确认弹窗 */}
      <Dialog open={showConfirm} onOpenChange={setShowConfirm}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>{t("exam.confirmStartTitle")}</DialogTitle>
            <DialogDescription>
              {t("exam.confirmStartDesc")}
            </DialogDescription>
          </DialogHeader>
          <DialogFooter>
            <Button variant="outline" onClick={() => setShowConfirm(false)}>
              {t("common.cancel")}
            </Button>
            <Button
              onClick={handleStart}
              disabled={startMutation.isPending}
            >
              {t("common.confirm")}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  )
}

import { useState, useCallback, useRef } from "react"
import { createFileRoute, useNavigate } from "@tanstack/react-router"
import { useTranslation } from "react-i18next"
import { toast } from "sonner"
import { Button } from "@/components/ui/button"
import { RadioGroup, RadioGroupItem } from "@/components/ui/radio-group"
import { Label } from "@/components/ui/label"
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
  DialogFooter,
} from "@/components/ui/dialog"
import { CountdownTimer } from "@/components/countdown-timer"
import { useSubmitExam } from "@/hooks/use-exams"
import type { StartExamResponse } from "@/hooks/use-exams"
import { cn } from "@/lib/utils"

/** 从 router location state 取出的考试数据 */
interface TakeExamState {
  recordId: number
  questions: StartExamResponse["questions"]
  startTime: string
  timeLimitMin: number
  examTitle: string
}

const OPTION_KEYS = ["A", "B", "C", "D"] as const

export const Route = createFileRoute("/_layout/exams/$id/take")({
  component: TakeExamPage,
})

function TakeExamPage() {
  const { t } = useTranslation()
  const navigate = useNavigate()
  const { id } = Route.useParams()
  const examId = Number(id)

  // 从 router state 获取考试数据
  const state = (Route.useRouteContext as any)() ?? {}
  const locationState = (window.history.state?.usr ?? {}) as Partial<TakeExamState>

  const recordId = locationState.recordId
  const questions = locationState.questions
  const startTime = locationState.startTime
  const timeLimitMin = locationState.timeLimitMin ?? 0
  const examTitle = locationState.examTitle ?? ""

  // 没有考试数据时跳回详情页
  if (!recordId || !questions?.length) {
    navigate({ to: `/exams/${examId}`, replace: true })
    return null
  }

  return (
    <TakeExamContent
      examId={examId}
      recordId={recordId}
      questions={questions}
      startTime={startTime!}
      timeLimitMin={timeLimitMin}
      examTitle={examTitle}
    />
  )
}

interface TakeExamContentProps {
  examId: number
  recordId: number
  questions: StartExamResponse["questions"]
  startTime: string
  timeLimitMin: number
  examTitle: string
}

function TakeExamContent({
  examId,
  recordId,
  questions,
  startTime,
  timeLimitMin,
  examTitle,
}: TakeExamContentProps) {
  const { t } = useTranslation()
  const navigate = useNavigate()
  const submitMutation = useSubmitExam()

  const [currentIndex, setCurrentIndex] = useState(0)
  const [answers, setAnswers] = useState<Record<number, string>>({})
  const [showConfirm, setShowConfirm] = useState(false)
  const submittingRef = useRef(false)

  const currentQuestion = questions[currentIndex]

  const handleSelectAnswer = (questionId: number, answer: string) => {
    setAnswers((prev) => ({ ...prev, [questionId]: answer }))
  }

  const doSubmit = useCallback(() => {
    // 防止重复提交（超时 + 手动同时触发）
    if (submittingRef.current) return
    submittingRef.current = true

    const answerList = questions.map((q) => ({
      questionId: q.id,
      answer: answers[q.id] ?? "",
    }))

    submitMutation.mutate(
      { examId, recordId, answers: answerList },
      {
        onSuccess: (res) => {
          toast.success(
            t("exam.submitSuccess", { score: res.score }),
          )
          navigate({ to: `/records/${recordId}`, replace: true })
        },
        onError: (err) => {
          toast.error(err.message)
          submittingRef.current = false
        },
      },
    )
  }, [answers, examId, navigate, questions, recordId, submitMutation, t])

  const handleTimeUp = useCallback(() => {
    toast.warning(t("exam.timeUp"))
    doSubmit()
  }, [doSubmit, t])

  const handleConfirmSubmit = () => {
    setShowConfirm(false)
    doSubmit()
  }

  const answeredCount = Object.keys(answers).length

  return (
    <div className="mx-auto max-w-3xl space-y-4">
      {/* 顶部栏：标题 + 倒计时 */}
      <div className="flex items-center justify-between rounded-lg border p-4">
        <h2 className="truncate text-lg font-semibold">{examTitle}</h2>
        {timeLimitMin > 0 && (
          <CountdownTimer
            startTime={startTime}
            timeLimitMin={timeLimitMin}
            onTimeUp={handleTimeUp}
          />
        )}
      </div>

      {/* 题目区域 */}
      <div className="rounded-lg border p-6 space-y-6">
        {/* 题号 */}
        <div className="text-sm text-muted-foreground">
          {t("exam.questionProgress", {
            current: currentIndex + 1,
            total: questions.length,
          })}
        </div>

        {/* 题目内容 */}
        <p className="text-base font-medium whitespace-pre-wrap">
          {currentQuestion.content}
        </p>

        {/* 选项 */}
        <RadioGroup
          value={answers[currentQuestion.id] ?? ""}
          onValueChange={(val) =>
            handleSelectAnswer(currentQuestion.id, val)
          }
          className="space-y-3"
        >
          {OPTION_KEYS.map((key) => {
            const optionField = `option${key}` as keyof typeof currentQuestion
            const optionText = currentQuestion[optionField] as string
            return (
              <div key={key} className="flex items-center gap-3">
                <RadioGroupItem value={key} id={`option-${key}`} />
                <Label
                  htmlFor={`option-${key}`}
                  className="cursor-pointer text-sm"
                >
                  {key}. {optionText}
                </Label>
              </div>
            )
          })}
        </RadioGroup>
      </div>

      {/* 底部导航 */}
      <div className="flex items-center justify-between">
        <div className="flex gap-2">
          <Button
            variant="outline"
            disabled={currentIndex <= 0}
            onClick={() => setCurrentIndex((i) => i - 1)}
          >
            {t("exam.prevQuestion")}
          </Button>
          <Button
            variant="outline"
            disabled={currentIndex >= questions.length - 1}
            onClick={() => setCurrentIndex((i) => i + 1)}
          >
            {t("exam.nextQuestion")}
          </Button>
        </div>
        <Button onClick={() => setShowConfirm(true)}>
          {t("common.submit")} ({answeredCount}/{questions.length})
        </Button>
      </div>

      {/* 题号网格 */}
      <div className="rounded-lg border p-4">
        <div className="flex flex-wrap gap-2">
          {questions.map((q, idx) => {
            const isAnswered = !!answers[q.id]
            const isCurrent = idx === currentIndex
            return (
              <button
                key={q.id}
                type="button"
                className={cn(
                  "flex h-8 w-8 items-center justify-center rounded text-sm font-medium transition-colors",
                  isAnswered && "bg-primary text-primary-foreground",
                  !isAnswered && !isCurrent && "bg-muted text-muted-foreground",
                  isCurrent && "ring-2 ring-primary ring-offset-1",
                )}
                onClick={() => setCurrentIndex(idx)}
              >
                {idx + 1}
              </button>
            )
          })}
        </div>
      </div>

      {/* 提交确认弹窗 */}
      <Dialog open={showConfirm} onOpenChange={setShowConfirm}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>{t("exam.confirmSubmitTitle")}</DialogTitle>
            <DialogDescription>
              {t("exam.confirmSubmitDesc", {
                answered: answeredCount,
                total: questions.length,
              })}
            </DialogDescription>
          </DialogHeader>
          <DialogFooter>
            <Button variant="outline" onClick={() => setShowConfirm(false)}>
              {t("common.cancel")}
            </Button>
            <Button
              onClick={handleConfirmSubmit}
              disabled={submitMutation.isPending}
            >
              {t("common.confirm")}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  )
}

import { useState } from "react"
import { createFileRoute, useNavigate } from "@tanstack/react-router"
import { useTranslation } from "react-i18next"
import { Button } from "@/components/ui/button"
import { Badge } from "@/components/ui/badge"
import {
  Table,
  TableHeader,
  TableBody,
  TableRow,
  TableHead,
  TableCell,
} from "@/components/ui/table"
import { useRecordList } from "@/hooks/use-records"
import type { RecordDetail } from "@/hooks/use-records"

export const Route = createFileRoute("/_layout/records/")({
  component: RecordListPage,
})

/** 记录状态 badge 变体映射 */
const STATUS_VARIANT: Record<string, "default" | "destructive"> = {
  submitted: "default",
  timeout: "destructive",
}

function formatStatus(status: string, t: (key: string) => string): string {
  const map: Record<string, string> = {
    submitted: t("exam.statusSubmitted"),
    timeout: t("exam.statusTimeout"),
    in_progress: t("exam.statusInProgress"),
  }
  return map[status] ?? status
}

function formatDateTime(dateStr: string | null): string {
  if (!dateStr) return "-"
  return new Date(dateStr).toLocaleString()
}

function RecordListPage() {
  const { t } = useTranslation()
  const navigate = useNavigate()
  const [page, setPage] = useState(1)
  const pageSize = 10
  const { data, isLoading } = useRecordList(page, pageSize)

  const totalPages = data ? Math.ceil(data.total / pageSize) : 0

  const handleRowClick = (record: RecordDetail) => {
    navigate({ to: `/records/${record.id}` })
  }

  return (
    <div className="space-y-4">
      <h1 className="text-xl font-semibold">{t("nav.records")}</h1>

      {isLoading ? (
        <div className="py-10 text-center text-muted-foreground">
          {t("common.loading")}
        </div>
      ) : !data?.records.length ? (
        <div className="py-10 text-center text-muted-foreground">
          {t("common.noData")}
        </div>
      ) : (
        <>
          <Table>
            <TableHeader>
              <TableRow>
                <TableHead>{t("exam.examTitle")}</TableHead>
                <TableHead>{t("exam.score")}</TableHead>
                <TableHead>{t("exam.status")}</TableHead>
                <TableHead>{t("exam.examTime")}</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {data.records.map((record) => (
                <TableRow
                  key={record.id}
                  className="cursor-pointer hover:bg-muted/50"
                  onClick={() => handleRowClick(record)}
                >
                  <TableCell className="font-medium">
                    {record.examTitle}
                  </TableCell>
                  <TableCell>
                    {record.score !== null
                      ? `${record.score}${t("exam.scoreUnit")}`
                      : "-"}
                  </TableCell>
                  <TableCell>
                    <Badge
                      variant={STATUS_VARIANT[record.status] ?? "default"}
                    >
                      {formatStatus(record.status, t)}
                    </Badge>
                  </TableCell>
                  <TableCell>{formatDateTime(record.startTime)}</TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>

          {/* 分页 */}
          {totalPages > 1 && (
            <div className="flex items-center justify-end gap-2">
              <Button
                variant="outline"
                size="sm"
                disabled={page <= 1}
                onClick={() => setPage((p) => p - 1)}
              >
                {t("exam.prevPage")}
              </Button>
              <span className="text-sm text-muted-foreground">
                {page} / {totalPages}
              </span>
              <Button
                variant="outline"
                size="sm"
                disabled={page >= totalPages}
                onClick={() => setPage((p) => p + 1)}
              >
                {t("exam.nextPage")}
              </Button>
            </div>
          )}
        </>
      )}
    </div>
  )
}

import { createFileRoute, useNavigate } from "@tanstack/react-router"
import { useTranslation } from "react-i18next"
import { ArrowLeft } from "lucide-react"
import { Button } from "@/components/ui/button"
import { Badge } from "@/components/ui/badge"
import { Separator } from "@/components/ui/separator"
import { useRecordDetail } from "@/hooks/use-records"
import { cn } from "@/lib/utils"

export const Route = createFileRoute("/_layout/records/$id")({
  component: RecordDetailPage,
})

const OPTION_KEYS = ["A", "B", "C", "D"] as const

/** 计算用时，返回格式化字符串 */
function formatDuration(
  startTime: string,
  endTime: string | null,
  t: (key: string, opts?: Record<string, unknown>) => string,
): string {
  if (!endTime) return "-"
  const diffMs = new Date(endTime).getTime() - new Date(startTime).getTime()
  const totalMin = Math.floor(diffMs / 60000)
  const secs = Math.floor((diffMs % 60000) / 1000)
  return t("exam.durationValue", { min: totalMin, sec: secs })
}

function RecordDetailPage() {
  const { t } = useTranslation()
  const navigate = useNavigate()
  const { id } = Route.useParams()
  const recordId = Number(id)
  const { data: record, isLoading } = useRecordDetail(recordId)

  if (isLoading) {
    return (
      <div className="py-10 text-center text-muted-foreground">
        {t("common.loading")}
      </div>
    )
  }

  if (!record) {
    return (
      <div className="py-10 text-center text-muted-foreground">
        {t("common.noData")}
      </div>
    )
  }

  const statusLabel =
    record.status === "submitted"
      ? t("exam.statusSubmitted")
      : record.status === "timeout"
        ? t("exam.statusTimeout")
        : t("exam.statusInProgress")

  const statusVariant =
    record.status === "timeout" ? "destructive" : "default"

  return (
    <div className="mx-auto max-w-3xl space-y-6">
      {/* 返回按钮 */}
      <Button
        variant="ghost"
        size="sm"
        onClick={() => navigate({ to: "/records" })}
      >
        <ArrowLeft className="mr-1 h-4 w-4" />
        {t("common.back")}
      </Button>

      {/* 成绩概要 */}
      <div className="rounded-lg border p-6 text-center space-y-3">
        <h2 className="text-lg font-semibold">{record.examTitle}</h2>
        <div className="text-4xl font-bold text-primary">
          {record.score !== null ? record.score : "-"}
          <span className="text-lg text-muted-foreground">
            {t("exam.scoreUnit")}
          </span>
        </div>
        <div className="flex items-center justify-center gap-4 text-sm text-muted-foreground">
          <Badge variant={statusVariant}>{statusLabel}</Badge>
          <span>
            {t("exam.duration")}:{" "}
            {formatDuration(record.startTime, record.endTime, t)}
          </span>
        </div>
      </div>

      {/* 答题明细 */}
      {record.answers?.length ? (
        <div className="space-y-4">
          <h3 className="text-base font-semibold">{t("exam.answerReview")}</h3>

          {record.answers.map((answer, idx) => (
            <div key={answer.questionId} className="rounded-lg border p-5 space-y-3">
              {/* 题号 + 内容 */}
              <p className="text-sm font-medium">
                <span className="text-muted-foreground">{idx + 1}. </span>
                {answer.content}
              </p>

              {/* 四个选项 */}
              <div className="space-y-1.5 pl-4">
                {OPTION_KEYS.map((key) => {
                  const optionField =
                    `option${key}` as keyof typeof answer
                  const optionText = answer[optionField] as string
                  const isUserAnswer = answer.userAnswer === key
                  const isCorrectAnswer = answer.correctAnswer === key

                  return (
                    <div
                      key={key}
                      className={cn(
                        "rounded px-2 py-1 text-sm",
                        isUserAnswer && answer.isCorrect && "bg-green-100 text-green-800",
                        isUserAnswer && !answer.isCorrect && "bg-red-100 text-red-800",
                        isCorrectAnswer && !isUserAnswer && "bg-green-50 text-green-700",
                      )}
                    >
                      {key}. {optionText}
                      {isUserAnswer && (
                        <span className="ml-2 text-xs font-medium">
                          [{t("exam.yourAnswer")}]
                        </span>
                      )}
                      {isCorrectAnswer && !isUserAnswer && (
                        <span className="ml-2 text-xs font-medium">
                          [{t("exam.correctAnswer")}]
                        </span>
                      )}
                    </div>
                  )
                })}
              </div>

              {/* 解析 */}
              {answer.analysis && (
                <>
                  <Separator />
                  <div className="rounded bg-muted p-3 text-sm text-muted-foreground">
                    <span className="font-medium">{t("exam.analysis")}: </span>
                    {answer.analysis}
                  </div>
                </>
              )}
            </div>
          ))}
        </div>
      ) : null}
    </div>
  )
}
